import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/launch-targets.DIrU2w_6.js";const s=JSON.parse(`{"title":"Запуск игры в VS Code","description":"Узнайте, как запустить лаунчер Minecraft из Visual Studio Code.","frontmatter":{"title":"Запуск игры в VS Code","description":"Узнайте, как запустить лаунчер Minecraft из Visual Studio Code.","authors":["dicedpixels"],"prev":{"text":"Открытие проекта в VS Code","link":"./opening-a-project"},"next":{"text":"Генерация исходных текстов в VS Code","link":"./generating-sources"},"files":[]},"headers":[],"relativePath":"ru_ru/develop/getting-started/vscode/launching-the-game.md","filePath":"translated/ru_ru/develop/getting-started/vscode/launching-the-game.md","lastUpdated":1770561656000}`);var c={name:`ru_ru/develop/getting-started/vscode/launching-the-game.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Запуск игры в VS Code <a class="header-anchor" href="#h1" aria-label="Permalink to “Запуск игры в VS Code”">​</a></h1><p>Инструментарий Fabric интегрируется с Visual Studio Code и предоставляет удобный способ запуска экземпляра игры для тестирования и отладки вашего мода.</p><h2 id="generating-launch-targets" tabindex="-1">Генерация целей запуска <a class="header-anchor" href="#generating-launch-targets" aria-label="Permalink to “Генерация целей запуска”">​</a></h2><p>Чтобы запустить игру с включенной поддержкой отладки, вам нужно сгенерировать цели запуска, выполнив задачу <code>vscode</code> Gradle.</p><p>Это можно сделать из Gradle View внутри Visual Studio Code: откройте его и перейдите к задаче <code>vscode</code> в разделе <strong>Задачи</strong> &gt; <strong><code>ide</code></strong>. Дважды щелкните или воспользуйтесь кнопкой <strong>Запустить задачу</strong>, чтобы выполнить задание.</p><p><img src="/assets/develop/getting-started/vscode/gradle-vscode.png" alt="vscode Задача в представлении Gradle" loading="lazy"></p><p>Также вы можете использовать терминал напрямую: откройте новый терминал через <strong>Терминал</strong> &gt; <strong>Новый терминал</strong> и запустите его:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./gradlew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vscode</span></span></code></pre></div><p><img src="/assets/develop/getting-started/vscode/terminal-vscode.png" alt="vscode Задание в терминале" loading="lazy"></p><h3 id="using-launch-targets" tabindex="-1">Использование целей запуска <a class="header-anchor" href="#using-launch-targets" aria-label="Permalink to “Использование целей запуска”">​</a></h3><p>После того как цели запуска сгенерированы, их можно использовать, открыв представление <strong>Запуск и отладка</strong>, выбрав нужную цель и нажав кнопку <strong>Начать отладку</strong> (<kbd>F5</kbd>).</p><p><img src="/assets/develop/getting-started/vscode/launch-targets.png" alt="Цели запуска" loading="lazy"></p>`,12)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};